import React from 'react';
import { Link } from 'react-router-dom';
import TopicsManager from './TopicsManager';
import './Sidebar.css';

function Sidebar({ blogs, loading, topics, selectedTopicId, onTopicSelect, onTopicsChange }) {
  return (
    <aside className="sidebar">
      <div className="sidebar-topic-label">Topics</div>
      <div className="sidebar-topics">
        <button
          type="button"
          className={`sidebar-topic sidebar-topic-button ${selectedTopicId === null ? 'active' : ''}`}
          onClick={() => onTopicSelect(null)}
        >
          All topics
        </button>
        {topics.length === 0 ? (
          <div className="sidebar-empty">No topics yet</div>
        ) : (
          topics.map(topic => {
            const topicId = topic.id || topic.name || topic;
            const topicName = topic.name || topic;

            return (
              <button
                type="button"
                key={topicId}
                className={`sidebar-topic sidebar-topic-button ${selectedTopicId === topicId ? 'active' : ''}`}
                onClick={() => onTopicSelect(topicId)}
              >
                {topicName}
              </button>
            );
          })
        )}
      </div>
      <TopicsManager topics={topics} onTopicsChange={onTopicsChange} />
    </aside>
  );
}

export default Sidebar;
